const raw = $input.first().json;
const orders = Array.isArray(raw) ? raw : [raw];
return orders.map(o => ({ json: { ...o, _platform: 'woocommerce' } }));

const items = $input.all();
const normalized =;

// Mapa de conversión de provincias a códigos ISO (Requerido por Envia.com)
const provinceMap = {
    "capital federal": "AR-C", "caba": "AR-C", "buenos aires": "AR-B", "catamarca": "AR-K",
    "chaco": "AR-H", "chubut": "AR-U", "córdoba": "AR-X", "cordoba": "AR-X",
    "corrientes": "AR-W", "entre ríos": "AR-E", "entre rios": "AR-E", "formosa": "AR-P",
    "jujuy": "AR-Y", "la pampa": "AR-L", "la rioja": "AR-F", "mendoza": "AR-M",
    "misiones": "AR-N", "neuquén": "AR-Q", "neuquen": "AR-Q", "río negro": "AR-R",
    "rio negro": "AR-R", "salta": "AR-A", "san juan": "AR-J", "san luis": "AR-D",
    "santa cruz": "AR-Z", "santa fe": "AR-S", "santiago del estero": "AR-G",
    "tierra del fuego": "AR-V", "tucumán": "AR-T", "tucuman": "AR-T"
};

function getIsoCode(province) {
    if (!province) return "AR-C";
    let p = province.toLowerCase().trim();
    // Si ya es un código ISO (empieza con AR-), lo dejamos como está
    if (p.startsWith("ar-")) return province.toUpperCase();
    return provinceMap[p] |

| "AR-C"; // Si no lo encuentra, por defecto CABA
}

for (const item of items) {
    const d = item.json;
    let out = {};

    if (d._platform === 'shopify') {
        out = {
            platform: 'shopify',
            order_id: String(d.id),
            order_number: String(d.order_number |

| d.name |
| d.id),
            customer_email: d.email |

| '',
            customer_name: `${d.customer?.first_name |

| ''} ${d.customer?.last_name |
| ''}`.trim(),
            customer_phone: (d.shipping_address?.phone |

| d.customer?.phone |
| '1100000000').replace(/[^0-9]/g, ''),
            shipping_street: d.shipping_address?.address1 |

| '',
            shipping_number: 'S/N',
            shipping_city: d.shipping_address?.city |

| '',
            shipping_province: getIsoCode(d.shipping_address?.province_code |

| d.shipping_address?.province),
            shipping_zipcode: d.shipping_address?.zip |

| '',
            order_total: parseFloat(d.total_price) |

| 1000,
        };
    } else if (d._platform === 'woocommerce') {
        const shipping = d.shipping |

| {};
        out = {
            platform: 'woocommerce',
            order_id: String(d.id),
            order_number: String(d.number |

| d.id),
            customer_email: d.billing?.email |

| '',
            customer_name: `${d.billing?.first_name |

| ''} ${d.billing?.last_name |
| ''}`.trim(),
            customer_phone: (d.billing?.phone |

| '1100000000').replace(/[^0-9]/g, ''),
            shipping_street: shipping.address_1 |

| '',
            shipping_number: shipping.address_2 |

| 'S/N',
            shipping_city: shipping.city |

| '',
            shipping_province: getIsoCode(shipping.state |

| d.billing?.state),
            shipping_zipcode: shipping.postcode |

| '',
            order_total: parseFloat(d.total) |

| 1000,
        };
    } else {
        // Tienda Nube
        out = {
            platform: 'tiendanube',
            order_id: String(d.id),
            order_number: String(d.number |

| d.id),
            customer_email: d.contact_email |

| '',
            customer_name: d.contact_name |

| '',
            customer_phone: (d.shipping_address?.phone |

| d.contact_phone |
| '1100000000').replace(/[^0-9]/g, ''),
            shipping_street: d.shipping_address?.address |

| '',
            shipping_number: d.shipping_address?.number |

| 'S/N',
            shipping_city: d.shipping_address?.city |

| '',
            shipping_province: getIsoCode(d.shipping_address?.province),
            shipping_zipcode: d.shipping_address?.zipcode |

| '',
            order_total: parseFloat(d.total) |

| 1000,
        };
    }
    normalized.push({ json: out });
}

return normalized;

const sheetsRows = $('📊 Sheets: Leer IDs Procesados').all();
const processedIds = new Set(
  sheetsRows.map(r => r.json.order_id).filter(id => id && id !== 'order_id')
);
const allOrders = $('⚙️ Normalizar Datos').all();
const newOrders = allOrders.filter(item => !processedIds.has(item.json.order_id));

if (newOrders.length === 0) {
  return [{ json: { _nada_que_procesar: true } }];
}
return newOrders;
// Código de TEST — reemplazar por el original al terminar
//return $input.all();

// Verificar que llegó un archivo PDF
const binaryData = $input.first().binary;
if (!binaryData || Object.keys(binaryData).length === 0) {
  throw new Error('No se recibió ningún archivo. Subí el PDF de etiquetas de Andreani.');
}

// Tomar el primer archivo binario que llegue
const fileKey = Object.keys(binaryData)[0];
const file = binaryData[fileKey];

if (!file.mimeType || !file.mimeType.includes('pdf')) {
  throw new Error('El archivo no es un PDF. Asegurate de subir el PDF de etiquetas de Andreani.');
}

return [{ json: { fileKey, fileName: file.fileName, mimeType: file.mimeType }, binary: binaryData }];

// ============================================================
// EXTRAER NÚMEROS DE SEGUIMIENTO DEL PDF DE ANDREANI
// ============================================================
// Las etiquetas de Andreani contienen:
// - Número de envío (tracking): empieza con '1' y tiene 14-16 dígitos
//   Ejemplo: 10000123456789
// - Número interno (referencia al pedido): puede ser el order_number
//   que pusiste al crear el envío. Lo busca en el campo 'descripcion'
//
// IMPORTANTE: Si los números de seguimiento de tu cuenta Andreani
// tienen un formato diferente, ajustá la regex en la línea marcada.
// ============================================================

const text = $input.first().json.text || '';

// Regex para capturar números de seguimiento de Andreani
// Formato habitual: comienza con 10 ó 1E seguido de dígitos, total 14-16 chars
// ⚠️ AJUSTÁ ESTA REGEX si tus trackings tienen otro formato:
const trackingRegex = /\b(1[0-9E]{13,15})\b/g;

// Regex para capturar número de pedido (lo que pusiste como 'descripcion' al crear el envío)
// El formato del workflow de carga es: "Pedido #NUMERO_PEDIDO [plataforma]"
const orderRegex = /Pedido\s*#(\d+)/gi;

// Dividir el PDF en bloques por etiqueta
// Las etiquetas de Andreani suelen separarse por ciertos patrones de texto
// Intentamos dividir por 'N° de envío' o 'Número de envío' o similares
let blocks = text.split(/(?=N[°o]?\.?\s*(?:de\s*)?env[ií]o)/gi);
if (blocks.length <= 1) {
  // Si no encuentra el patrón, intentar dividir por doble salto de línea + tracking
  blocks = text.split(/(?=\b1[0-9E]{13,15}\b)/);
}
if (blocks.length <= 1) {
  blocks = [text]; // Usar todo el texto como un bloque si no puede dividir
}

const trackings = [];

for (const block of blocks) {
  const trackingMatches = [...block.matchAll(trackingRegex)];
  const orderMatches = [...block.matchAll(orderRegex)];

  if (trackingMatches.length > 0) {
    const trackingNumber = trackingMatches[0][1];
    const orderNumber = orderMatches.length > 0 ? orderMatches[0][1] : null;

    // Evitar duplicados
    if (!trackings.find(t => t.tracking_number === trackingNumber)) {
      trackings.push({
        tracking_number: trackingNumber,
        order_number: orderNumber,
        raw_block: block.substring(0, 200) // primeros 200 chars para debug
      });
    }
  }
}

if (trackings.length === 0) {
  throw new Error(`No se encontraron números de seguimiento en el PDF. Verificá que el PDF sea de etiquetas de Andreani. Texto extraído (primeros 500 chars): ${text.substring(0, 500)}`);
}

console.log(`✅ Se encontraron ${trackings.length} números de seguimiento en el PDF`);
return trackings.map(t => ({ json: t }));

// ============================================================
// CRUZAR TRACKING CON PEDIDO EN EL GOOGLE SHEET
// ============================================================
// Tomamos los trackings extraídos del PDF y los cruzamos con
// los datos del Sheet para obtener order_id, platform, email.
// ============================================================

const sheetsRows = $('📊 Sheets: Buscar Pedido por N°').all();
const trackingItems = $input.all();
const results = [];

for (const item of trackingItems) {
  const { tracking_number, order_number } = item.json;

  // Buscar en el Sheet la fila correspondiente
  let matchedRow = null;

  if (order_number) {
    // Buscar por número de orden (más confiable)
    matchedRow = sheetsRows.find(r => 
      String(r.json.order_number) === String(order_number)
    );
  }

  if (!matchedRow) {
    // Si no encontró por order_number, buscar por estado CARGADO_SIN_TRACKING
    // y tomar el más reciente (puede ser impreciso si hay muchos)
    const pending = sheetsRows.filter(r => r.json.estado === 'CARGADO_SIN_TRACKING');
    if (pending.length > 0 && order_number === null) {
      // Solo usar este fallback si hay exactamente un pendiente
      matchedRow = pending.length === 1 ? pending[0] : null;
    }
  }

  if (matchedRow) {
    results.push({
      json: {
        tracking_number,
        order_number: matchedRow.json.order_number,
        order_id: matchedRow.json.order_id,
        platform: matchedRow.json.platform,
        customer_email: matchedRow.json.customer_email,
        matched: true
      }
    });
  } else {
    // No se encontró match — loguear para revisión manual
    results.push({
      json: {
        tracking_number,
        order_number,
        order_id: null,
        platform: null,
        customer_email: null,
        matched: false,
        error: `No se encontró pedido con order_number=${order_number} en el Sheet`
      }
    });
  }
}

return results;
